on(){		slideto(1);	});	$(document).onSwipe({direction:'left-edge'},function(){		if($( "#sidebar" ).is('.side_bar_off')){			$( "#sidebar" ).removeClass("side_bar_off").addClass("side_bar_on");		}		else{			$( "#sidebar" ).removeClass("side_bar_on").addClass("side_bar_off");		}	});		// $(document).on('touchstart',function(e){		// e.stopPropagation(); 		// e.preventDefault();		// alert('doc');	// });		// $(document).on('touchmove', function(e){		// e.preventDefault();		// var touch = e.touches[0];		// alert(touch.pageX + " - " + touch.pageY);	// });		// $(document).on('touchend', function(e){		// e.stopPropagation();        // e.preventDefault();		// alert('doc');    // });		$.fn.request_full_screen = function() {		if(this.requestFullscreen){			this.requestFullscreen();			return true;		}else if(this.mozRequestFullScreen){			this.mozRequestFullScreen();			return true;		}else if(this.webkitRequestFullScreen){			this.webkitRequestFullScreen();			return true;		}else if(this.msRequestFullscreen){			this.msRequestFullscreen();			return true;		}		return false;	};		$('#show_side_bar2,#hamburger').on('click',function(e){		if($( "#sidebar" ).is('.side_bar_off')){			$( "#sidebar" ).removeClass("side_bar_off").addClass("side_bar_on");		}		else{			$( "#sidebar" ).removeClass("side_bar_on").addClass("side_bar_off");		}	e.stopPropagation();	});		$('#drop_down').on('click',function(e){		if($( "#drop_down > ul" ).is('.showi')){			$( "#drop_down > ul" ).removeClass("showi").addClass("hidei");		}		else{			$( "#drop_down > ul" ).removeClass("hidei").addClass("showi");		}				if($('body').request_full_screen()){			alert();		}	e.stopPropagation();	});		$(document).on('click',function(e){		if($(e.target).is('#sidebar,#side_top,#drop_down > ul > li')==false){			if($( "#sidebar" ).is('.side_bar_on')){				$( "#sidebar" ).removeClass("side_bar_on").addClass("side_bar_off");				e.stopPropagation();			}			if($( "#drop_down > ul" ).is('.showi')){				$( "#drop_down > ul" ).removeClass("showi").addClass("hidei");			}		}	});		setTimeout(function(){		$('#mSg').slideUp(500);	},3000);		setInterval(function() {		$.ajax({			type: "GET",			url: "ajax_chk_login.php",			dataType: "text",			data: "ivk=ajx",			success: function(msg){				if(msg!=1)					location.href='index.php';			}		}).fail(function() {		});	}, 10000);});</script>